-- Run this once in the Supabase SQL editor (Project > SQL Editor > New query)

create table if not exists public.blogs (
  id bigint generated always as identity primary key,
  slug text unique not null,
  category text not null,
  read_time text not null,
  title text not null,
  excerpt text not null,
  author text not null,
  author_img text not null,
  date text not null,
  img text not null,
  content jsonb not null default '[]'::jsonb
);

alter table public.blogs enable row level security;

create policy "Public read access" on public.blogs
  for select using (true);

insert into public.blogs (slug, category, read_time, title, excerpt, author, author_img, date, img, content) values
('20-myths-about-clat-pg', 'CLAT PG', '8 MIN', '20 Myths About CLAT PG You Should Stop Believing', 'From ''only toppers get into NLUs'' to ''coaching guarantees a seat'' — we bust the myths holding back aspirants every year.', 'Bhavtosh', 'https://picsum.photos/seed/bhavtosh/64/64', 'June 13, 2026', 'https://picsum.photos/seed/blog-hero/900/600', '[{"type":"heading","text":"Why CLAT PG myths matters more than you think"},{"type":"paragraph","text":"Most students approach clat pg myths the wrong way — cramming information without understanding how it''s actually applied. In this article, we break down a mentor-tested approach that focuses on clarity over volume."},{"type":"heading","text":"Where most students go wrong"},{"type":"quote","text":"\"It''s not about how many hours you put in — it''s about whether those hours are aimed at the right targets.\" Mentors at The Law Project repeat this to every new batch, and it holds true across every stage of preparation."},{"type":"paragraph","text":"The biggest mistake we see is treating preparation as a single long sprint instead of a series of focused cycles. Breaking your effort into smaller, reviewable blocks makes it far easier to spot gaps early and fix them before they compound."},{"type":"numbered","items":["Start with a diagnostic to identify your actual weak areas","Build a focused study cycle around those gaps","Review with a mentor before moving to the next topic","Track progress weekly, not just before the exam"]},{"type":"heading","text":"A practical framework to follow"},{"type":"paragraph","text":"Once you know where you stand, the next step is building a routine that compounds. Consistency beats intensity almost every time — a steady one hour a day outperforms a chaotic weekend cram session."},{"type":"bulleted","items":["Block dedicated time for active practice, not just reading","Get feedback from a mentor or peer regularly","Revisit older topics on a rolling schedule","Simulate real exam or interview conditions before the actual day"]}]'::jsonb),
